import{_ as r,o as t,c as n,ag as i}from"./chunks/framework.DXGyWiRo.js";const o="/images/uebung098.jpg",a="/images/uebung099.jpg",g=JSON.parse('{"title":"Übung Lektion 59","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung59.md","filePath":"lektionen/uebung59.md"}'),s={name:"lektionen/uebung59.md"};function u(b,e,p,h,l,c){return t(),n("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-59" tabindex="-1">Übung Lektion 59 <a class="header-anchor" href="#ubung-lektion-59" aria-label="Permalink to &quot;Übung Lektion 59&quot;">​</a></h1><p><img src="'+o+'" alt=""><br> Abb.: रावणः<br> Yakshagana  = ಯಕ್ಷಗಾನ<br> [Bildquelle: Ganapiti / Wikipedia. GNU FDLicense]</p><p>A) Übersetzen Sie den folgenden Text und bestimmen Sie alle darin vorkommenden Verbalformen.</p><p>Die Übersetzung ist bewusst holprig gelassen, um als Übersetzungshilfe zu dienen.</p><p><em>Übersetzungshilfe:</em> Vers 6: दिदृक्षते = Desiderativ zu दृश्</p><p>Text aus: Otto Böhtlingk: Sanskrit-Chrestomathie S. 127f.</p><p>राक्षसेन्द्रस्ततो ऽभैषीदैक्षिष्ट परितः पुरम् ।<br> प्रातिष्ठिपच्च बोधार्थं कुम्भकर्णस्य राक्षसान् ॥१॥</p><blockquote><p>Darauf fürchtete sich der Dämonenfürst. Er blicktein der Stadt rundherum und schickte die Rākṣasa, Kumbhakarṇa1 zu wecken.</p><p>अभैषीत् -  भी Aor. 4 P<br> ऐक्षिष्ट - ईक्ष् Aor. 5 Ā<br> प्रातिष्ठिपत् - प्र-स्था unregelm. (siehe Pāṇini 7.4.5) Aor. 3</p><p>1 Kumbhkarṇa, der Bruder Rāvaṇas, liegt als Strafe für seine Übeltaten im Dauerschlaf</p></blockquote><p>ते ऽभ्यगुर्भवनं तस्य सुप्तं चैक्षिषताथ तम् ।<br> व्याहार्षुस्तुमुलाञ्छब्दान्दण्डैश्चावधिषुर्द्रुतम् ॥२॥</p><blockquote><p>Diese gingen zu dessen Haus und erblickten diesen schlafend. Sie riefen tumultöse Laute und schlugen schnell mit Stöcken.</p><p>अभ्यगुर् - अभि-गा (für इ) Aor. 1 P<br> अक्षिषत - ईक्ष् Aor. 5 Ā (3.pl.)<br> व्याहार्षुर् - वि-आ-हृ aussprechen, sagen Aor. 4 P<br> अवधिषुर् - वध् (statt हन्) Aor. 5</p></blockquote><p>केशानलुञ्चिषुस्तस्य गजान्गात्रेष्वभिभ्रमन् ।<br> शीतैरभ्यषिचंस्तोयैरलातैश्चाप्यदम्भिषुः ॥३॥</p><blockquote><p>Sie zerrten seine Haare, ließen Elefanten auf seinen Gliedern herumirren; sie besprengten ihn mit kaltem Wasser und verletzten ihn mit Feuern.</p><p>अलुञ्चिषुर् - लुञ्च् Aor. 5<br> अबिभ्रमन् - भ्रम् Kaus. Aor. 3<br> अभ्यषिचन् - सिच् Aor. 2<br> अदम्भिषुर् - दम्भ् Aor. 5</p></blockquote><p>नखैरकर्तिषुस्तीक्ष्णैरदाङ्क्षुर्दशनैस्तथा ।<br> शितैरतौत्सुः शूलैश्च भेरीश्चावीवदञ्छुभाः ॥४॥</p><blockquote><p>Sie schnitten ihn mit scharfen Fingernägeln und sie bissen ihn mit den Zähnen, sie schlugen ihn mit scharfen Spießen und sie ließen helle Trommeln ertönen.</p><p>अकर्तिषुर् - कृत् Aor. 5<br> अदाङ्क्षुर् - दंश् Aor. 4<br> अतौत्सुर् - तुद् Aor. 4<br> अवीवदन् - वद् Kaus. Aor. 4</p></blockquote><p>स तान्नाजीगणत्सर्वानिच्छयाबुद्ध च स्वयम् ।<br> अबूबुधत कस्मान्मामप्राक्षीच्च निशाचरान् ॥५॥</p><blockquote><p>Er beachtete diese alle nicht, durch Wunsch erwachte er selbst und er fragte die Nachtwandler: &quot;Warum habt ihr mich geweckt?&quot;</p><p>अजीगणत् - गण् 10 Aor 3<br> अबुद्ध - बुध् Aor 4 (neben अबोधि)<br> अबुबूधत - बुध् Kaus. Aor. 3 (2.pl.P)<br> अप्राक्षीत् - प्रछ् Aor 4</p></blockquote><p>ते ऽभाषिषत राजा त्वां दिदृक्षुः क्षणदाचर ।<br> सो ऽस्नासीद्व्यलिपन्मांसमप्सासीद्वारुणीमपात् ॥६॥</p><blockquote><p>Diese sprachen: &quot;Der König ist begierig, dich zu sehen, Nachtwandler!&quot; Er badete, cremte sich, verschlang Fleisch, trank Palmschnaps;</p><p>अभाषिषत - भाष् Ā Aor. 5<br> अस्नासीत् - स्ना Aor. 6<br> व्यलिपत् - वि-लिप् Aor. 2<br> अप्सासीत् - प्सा Aor. 6<br> अपात् - पा Aor. 1</p></blockquote><p>न्यवसिष्ट ततो द्रष्टुं रावणं प्रावृतद्गृहात् ।<br> राजायान्तं तमद्राक्षीदुदस्थाच्चेषदासनात् ॥७॥</p><blockquote><p>Er zog sich an, dann ging er von zuhause weg, um Rāvaṇa zu sehen. Der König sah in kommen und stand ein wenig vom Sitz auf.</p><p>न्यवसिष्ट - नि-वस् 2Ā Aor. 5<br> प्रावृतत् - प्र-वृत् Ā Aor. 2 P (im Aor. auch P!)<br> अद्राक्षीत् - दृश्  Aor. 4<br> उदस्थात् - उद्-स्था Aor. 1</p></blockquote><p>अतुषत्पीठमासन्ने निरदिक्षच्च काञ्चनम् ।<br> अस्मेष्ट कुम्भकर्णो ऽल्पमुपाविक्षदथान्तिके ॥८॥</p><blockquote><p>Er war zufrieden und wies ihm einen goldenen Stuhl in der Nähe an. Kumbhkarṇa lächelte ein wenig und setzte sich dann in die Nähe.</p><p>अतुषत् - तुष् Aor. 2<br> निरदिक्षत् - निर्-दिश् Aor. 7<br> अस्मेष्ट - स्मि Ā Aor. 4<br> उपाविक्षत् - उप-विश् Aor. 7</p></blockquote><p>अवादीन्मां किमित्याह्वो राज्ञा च प्रत्यवादि सः ।<br> नाज्ञासीस्त्वं सुखी रामो यदकार्षीत्स रक्षसाम् ॥९॥</p><blockquote><p>Er sprach. &quot;Warum hast du mich gerufen?&quot; Ihm wurde vom König geantwortet: &quot;Du Glücklicher hast nicht erkannt, was Rāma den Dämonen getan hat.</p><p>अवादीत् - वद् Aor. 5<br> आह्वस् - आ-ह्वे Aor. 2<br> प्रत्यवादि - प्रति-वद् Passivaorist<br> अज्ञासीस् - ज्ञा Aor. 6<br> अकार्षीत् - कृ Aor. 4</p></blockquote><p>उदतारीदुदन्वन्तं पुरं नः परितो ऽरुधत् ।<br> व्यद्योतिष्ट रणे शस्त्रैरनैषीद्राक्षसान्क्षयम् ॥१०॥</p><blockquote><p>Er hat den Ozean überquert, unsere Stadt rundherum blockiert, er hat in der Schlacht mit Schneidewaffen aufgeleuchtet, er führte die Dämonen zur Vernichtung.</p><p>उदतारीत् - उद्-तॄ Aor. 5<br> अरुधत् - रुध् Aor. 2<br> व्यद्योतिष्ट - वि-द्युत्  Aor. 5<br> अनैषीत् - नी Aor. 4</p></blockquote><p>न प्रावोचमहं किंचित्प्रियं यावदजीविषम् ।<br> बन्धुस्त्वमर्चितः स्नेहान्मा द्विषो न वधीर्मम ॥११॥</p><blockquote><p>Ich habe, solange ich lebte, keine Schmeichelei gesagt. Du bist mein aus Liebe verehrter Verwandter. Unterlasse es nicht, meine Feinde zu erschlagen!</p><p>प्रावोचम् - प्र-वच् Aor. 3<br> अजीविषम् - जीव् Aor. 5<br> वधीस् - वध् Injunktiv Aor. 5</p></blockquote><p>वीर्यं मा न ददर्शस्त्वं मा न त्रास्थाः क्षतां पुरम् ।<br> तवाद्राक्ष्म वयं वीर्यं त्वमजैषीः पुरा सुरान् ॥१२॥</p><blockquote><p>Unterlasse es nicht, deine Manneskraft zu zeigen, unterlasse es nicht, die die verletzte Stadt zu retten! Wir haben deine Manneskraft gesehen. Du hast früher die Götter besiegt.&quot;</p><p>ददर्शस् - दृश् Kaus. Injunktiv Aor. 3<br> त्रास्थास् - त्रै Ā Injunktiv. Aor. 4<br> अद्राक्ष्म - दृश् Aor. 4<br> अजैषीस् - जि Aor. 4</p></blockquote><p>अवोचत्कुम्भकर्णस्तं वयं मन्त्रे ऽभ्यधाम यत् ।<br> न त्वं सर्वं तदश्रौषीः फलं तस्येदमागमत् ॥१३॥</p><blockquote><p>Kumbhakarṇa sprach zu ihm: &quot;Was wir bei der Beratung dargelegt haben, auf all dies hast du nicht gehört. Dies ist als Frucht davon gekommen.</p><p>अवोचत् - वच् Aor. 3<br> अभ्यधाम - अभि-धा Aor. 1<br> अश्रौषीस् - श्रु Aor. 4<br> आगमत् - आ-गम् Aor. 2</p></blockquote><p>प्राज्ञवाक्यान्यवामामंस्था मूर्खवाक्येष्ववास्थिथाः ।<br> अध्यगीष्ठाश्च शास्त्राणि प्रत्यपत्था हितं न च ॥१४॥</p><blockquote><p>Du hast die Worte der Weisen verachtet, du hast dich auf Worte von Dummen gestellt, du hast die Lehrwerke studiert und bist [trotzdem] nicht zum Heilsamen gegangen.</p><p>अवामामंस्थास् - अव-मन् Aor. 4<br> अवास्थिथास् - अव-स्था Aor. 4<br> अध्यगीष्ठास् - अधि-इ (अधि-गा) Aor. 4<br> प्रत्यपत्थास् - प्रति-पद् Aor. 4</p></blockquote><p>मूर्खास्त्वामववञ्चन्त ये विग्रहमचीकरन् ।<br> अभाणीन्माल्यवान्युक्तमक्षंस्थास्त्वं न तन्मदात् ॥१५॥</p><blockquote><p>Die Dummen, die den Zwist bewirkten, haben dich getäuscht. Mālyavant1 sprach das Passende. Du hast nicht verziehen aus Rausch gegen ihn.</p><p>अववञ्चन्त - वञ्च् Kaus. Aor. 3<br> अचीकरन् - कृ Aor. 3<br> अभाणीत् - भण् Aor. 5<br> अक्षंस्थास् - क्षम् Aor. 4</p><p>1 ein Rākṣasa</p></blockquote><p>राघवस्यामुषः कान्तामाप्तैरुक्तो न चार्पिपः ।<br> मा नानुभूः स्वकान्दोषान्मा मुहो मा रुषो ऽधुना ॥१६॥</p><blockquote><p>Du hast die Geliebte des Raghunachkommen1 gestohlen. Obwohl es dir von Autoritätspersonen gesagt wurde, hast du sie nicht zurückgeschickt. Hör auf, deine eigenen Fehler nicht wahrzunehmen! Sei nicht wirr, zürne jetzt nicht!</p><p>अमुषस् - मुष् Aor. 2<br> आर्पि्पस् - ऋ Kaus. Aor. 3<br> अनुभूस् - अनु-भू Injunktiv Aor. 1<br> मुहस् - मुह् Injunktiv Aor. 2<br> रुषस् - रुष् Injunktiv Aor. 2</p><p>1 Rāma</p></blockquote><p>तस्याप्यत्यक्रमीत्कालो यत्तदाहमवादिषम् ।<br> अघानिषत रक्षांसि परैः कोशांस्त्वमव्ययीः ॥१७॥</p><blockquote><p>Für das, was ich dir damals sagte, ist der rechte Zeitpunkt vergangen. Die Rakṣas wurden von den Feinden getötet. Du hast die Schätze verloren.</p><p>अत्यक्रमीत् - क्रम् Aor. 5<br> अवादिषम् - वद् Aor. 5<br> अघानिषत - हन् Passivaorist 3.pl.<br> अव्ययीस् - व्यय् Aor. 5</p></blockquote><p>संधानकारणां तेजो न्यगभूत्ते ऽकृथास्तथा ।<br> यत्त्वं वैराणि कोशं च सहदण्डमजिग्लपः ॥१८॥</p><blockquote><p>Deine Macht, die Ursache für eine Allianz, wurde niedrig. Du hast so gehandelt, dass du deine Heere und deinen Schatz samt der politischen Macht dahinschwinden machtest.&quot;</p><p>अभूत् - भू Aor. 1<br> अकृथास् - कृ Aor. 4/1<br> अजिग्लपस् - ग्लै Kaus. Aor. 3</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: रामस्य रावणेन युद्धः<br> Wat Phra Kaew = วัดพระแก้ว, Bangkok = กรุงเทพฯ<br> [Bildquelle: Wikipedia. Public domain]</p>',44)])])}const k=r(s,[["render",u]]);export{g as __pageData,k as default};
